    if (delErr) { setError("Failed to delete chat"); setDeletingId(null); return; }
    setChats((prev) => prev.filter((c) => c.id !== chatId));
    if (activeChat?.id === chatId) { setActiveChat(null); setPrompt(""); }
    setDeletingId(null);
